final:
module top_module(
    input A,
    input B,
    input C,
    input D,
    input S0,
    input S1,
    output Y
);wire inv_notS0, notS1;

    assign inv_notS0 = ~S0;
    assign notS1 = ~S1;

    // Compute the output signal
    assign Y = (A & notS1 & inv_notS0) |
               (B & notS1 & S0) |
               (C & S1 & inv_notS0) |
               (D & S1 & S0);

endmodule
